<section class="admin-page-head"><div><p class="eyebrow">COMANDĂ</p><h1><?= e($order['order_number']) ?></h1><p><?= e($order['email']) ?> · <?= date('d.m.Y H:i',strtotime($order['created_at'])) ?></p></div><div class="button-row"><form method="post" action="<?= e(url('/admin/comenzi/'.$order['id'].'/factura')) ?>"><?= csrf_field() ?><button class="admin-button" type="submit">Emite factura</button></form><a class="admin-button secondary" href="<?= e(url('/admin/comenzi/'.$order['id'].'/awb')) ?>">Livrare și AWB</a></div></section><?php if(!empty($notice)): ?><div class="admin-alert success"><?= e($notice) ?></div><?php endif; ?><?php if(!empty($error)): ?><div class="admin-alert error"><?= e($error) ?></div><?php endif; ?><div class="admin-two-columns"><div><section class="admin-panel"><div class="panel-head"><h2>Produse comandate</h2></div><?php foreach($items as $item): ?><div class="admin-order-item"><div><strong><?= e($item['name_snapshot']) ?></strong><small><?= e($item['sku_snapshot']) ?> · <?= (int)$item['quantity'] ?> buc.</small></div><b><?= money($item['total_minor']) ?></b></div><?php endforeach; ?><div class="admin-order-total"><span>Total</span><strong><?= money($order['grand_total_minor']) ?></strong></div></section><section class="admin-panel"><h2>Istoric și note</h2><ol class="admin-timeline"><?php foreach($history as $event): ?><li><strong><?= e($event['new_status']) ?></strong><span><?= e($event['public_message']) ?></span><time><?= date('d.m.Y H:i',strtotime($event['created_at'])) ?></time></li><?php endforeach; ?></ol><?php foreach($notes as $note): ?><blockquote><p><?= e($note['note']) ?></p><small><?= e($note['author']??'Sistem') ?> · <?= date('d.m.Y H:i',strtotime($note['created_at'])) ?></small></blockquote><?php endforeach; ?></section></div><aside><section class="admin-panel"><h2>Status comandă</h2><form method="post" action="<?= e(url('/admin/comenzi/'.$order['id'].'/status')) ?>"><?= csrf_field() ?><label>Status nou<select name="status" required><?php foreach(['confirmed','processing','ready_for_shipping','shipped','delivered','cancelled','return_requested','returned','partially_refunded','refunded'] as $status): ?><option value="<?= e($status) ?>"><?= e($status) ?></option><?php endforeach; ?></select></label><label>Mesaj public<textarea name="public_message"></textarea></label><label>Notă internă<textarea name="internal_note"></textarea></label><label class="check-label"><input type="checkbox" name="notify" value="1" checked> Notifică clientul prin email</label><button class="admin-button" type="submit">Actualizează statusul</button></form></section><section class="admin-panel"><h2>Client și plată</h2><dl class="admin-details"><dt>Tip client</dt><dd><?= e($order['customer_type']) ?></dd><dt>Plată</dt><dd><?= e($order['payment_method']) ?> / <?= e($order['payment_status']) ?></dd><dt>Livrare</dt><dd><?= e($order['shipping_method']) ?></dd><?php if($shipment): ?><dt>AWB</dt><dd><?= e($shipment['awb']?:'În pregătire') ?></dd><?php endif; ?></dl></section></aside></div>

